var b="url",c="采购入库__240704_.html",d="generationDate",e=new Date(1781494400676.85),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="NewVariable",s="page",t="packageId",u="ac0175d629f5425baf788ef14f44dfcc",v="type",w="Axure:Page",x="采购入库 (240704)",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="f6c186eef39e44e99b523aa31f07d732",E="label",F="选项1",G="说明",H="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.数据来源：全部'已通过'的采购订单(CGDD)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.模糊搜索</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.提示字：单号/供应商/包含物料</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.支持对采购单上“采购订单号”、“供应商”、[采购清单]中“物料编码”或“物料名称”的模糊搜索</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; c.右侧含'×'的快捷清除按钮</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; d.点击【查找】后生效</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">3.快捷筛选：展示已完成的采购单</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.不勾选(默认)：仅展示'待入种类'＞0的采购单</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.勾选：展示全部采购单</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">4.卡片描述：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">卡片高度根据行数自适应</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.关联生产</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a1.取值：采购清单中全部的“关联生产”去重后按行展示，有几个关联生产订单就展示几行</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a2.展示：'</span><span style=\"color:#4B7902;\">关联生产</span><span>'+'</span><span style=\"color:#0000FF;\">(</span><span>'+'</span><span style=\"color:#4B7902;\">自定义单号</span><span>'+'</span><span style=\"color:#0000FF;\">)</span><span>'；其中，'自定义单号'为空时，无须使用括号拼接</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; </span><span>b.待入种类：采购订单内'已申请入库＜实际采购数量'的SKU行数</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; </span><span>c.待入数量：待入SKU中 Σ 实际采购数量-已申请入库 (附：不要跟超过原定入库数量的部分相冲)</span></p>",I="2",J="6803343435884609aa35fa70f56fe0e8",K="选项2",L="<p><span>1.卡片：关联生产</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.取值：'</span><span style=\"color:#4B7902;\">关联生产</span><span>'+'</span><span style=\"color:#0000FF;\">(</span><span>'+'</span><span style=\"color:#4B7902;\">自定义单号</span><span>'+'</span><span style=\"color:#0000FF;\">)</span><span>'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a1.'自定义单号'为空时，无须使用括号拼接</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.若'关联生产'为空，卡片不展示该行</span></p>",M="3",N="bb8f95f486a948cf9571e86aa4bd1768",O="(矩形)",P="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#D9001B;\">点击卡片，视为对当前采购订单的入库</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.将“采购关联单”信息传给[入库列表]页面</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.获取当前用户在该采购订单上历史缓存的入库清单</span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">调用摄像头，进行扫码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.校验识别的字符串是否为系统内生成过的“唯一码”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.生成过：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.未生成：返回Toast提示‘未生成的物料唯一码’；停留在当前列表页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.若[配置管理&gt;&gt;仓库配置：采购入库范围]为“仅单据物料”时，校验识别的“唯一码”所属的SKU是否为当前采购单中包含的</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.是单据物料：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.非单据物料：Toast提示‘仅支持单据内物料’；停留在当前列表页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">通过校验，将识别的'唯一码'及相关参数传至[入库信息页]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.若“唯一码”已存在于本次入库的[入库明细]中，将已填写的入库信息(全部字段)传至[入库信息页]后支持修改</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.若“唯一码”未存在于本次入库的[入库明细]中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.本次扫码：初始化为0</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.累计入库：初始化为0</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; c.将识别出的'唯一码'及唯一码对应的物料信息(物料名称、编码、颜色、规格)至[入库信息页]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; d.</span><span>根据识别的“唯一码”是否在[当前采购入库明细]中、[物料库存日志-明细日志]中存在记录，对字段中</span><span style=\"color:#02A7F0;\">赋默认值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.不存在于[当前采购入库明细](新增)，无[物料库存日志-明细日志]记录：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">全部可编辑字段均为空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.不存在于[当前采购入库明细](新增)，有[物料库存日志-明细日志]记录：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">清空'数量'编辑域的值，其他字段取唯一码上已有值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iii.存在于[当前采购入库明细](编辑)：取已填写的值，用于修改</span></p>",Q="4",R="90fd4b9cc410437faff9c80d40d0aa0b",S="物料：",T="<p><span>1.展示方式为 '</span><span style=\"color:#02A7F0;\">物料名称</span><span>'+'</span><span style=\"color:#02A7F0;\">(</span><span>'+'</span><span style=\"color:#02A7F0;\">物料编码</span><span>'+'</span><span style=\"color:#02A7F0;\">)</span><span>'</span></p><p><span>2.若超出单行宽度时换行展示，注意换行开始的位置是展示字段不是从标题开始</span></p>",U="5",V="6956a2a94e5a4f1b99939b398f370a25",W="颜色：",X="<p><span>1.若超出单行宽度时换行展示，注意换行开始的位置是展示字段不是从标题开始</span></p>",Y="6",Z="40888089e6214e4f8b7d00be4b35b252",ba="缸号：",bb="<p><span style=\"color:#333333;\">默认值</span></p><p><span style=\"color:#333333;\">1.若为已扫码的唯一码修改，将原有信息带入</span></p><p><span style=\"color:#333333;\">2.若上个入库信息的唯一码</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">所属的</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#02A7F0;\">SKU与当前的一致</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">，将缓存的对应字段作为默认值</span></p>",bc="7",bd="6809c00ed8f848018c3e004018c89672",be="卷号：",bf="8",bg="dd154e0a805f4a4098c4db216bc3b002",bh="批次号：",bi="9",bj="e8ae8adef97e4fe79ec4ca1b98e06939",bk="备注：",bl="<p><span style=\"color:#333333;\">默认值</span></p><p><span style=\"color:#333333;\">1.若为已扫码的唯一码修改，将原有信息带入</span></p><p><span style=\"color:#333333;\">2.否则默认为空</span></p>",bm="10",bn="6f5bb39f103b4af4854ed796c2ae0a45",bo="* 数量：",bp="<p><span>数据格式：保留两位小数</span></p><p><span><br></span></p><p><span>默认值</span></p><p><span>1.若为已扫码的唯一码修改，将原有信息带入</span></p><p><span>2.否则默认为空</span></p>",bq="11",br="abd6a067a59f467db94dbaf9dafcf6d4",bs="继续扫码",bt="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">校验当前“数量”编辑域</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">1.“数量”非空且＞0：通过校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">2.“数量”空或≤0：Toast提示'请输入数量'</span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">调用摄像头，进行扫码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.校验识别的字符串是否为系统内生成过的“唯一码”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.生成过：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.未生成：返回Toast提示‘未生成的物料唯一码’；停留在当前入库信息页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.若[配置管理&gt;&gt;仓库配置：采购入库范围]为“仅单据物料”时，校验识别的“唯一码”所属的SKU是否为当前采购单中包含的</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.是单据物料：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.非单据物料：Toast提示‘仅支持单据内物料’；停留在当前入库信息页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">通过校验，将识别的新'唯一码'及相关参数传至[入库信息页]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.校验识别的新“唯一码”是否存在于本次扫码中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.未存在：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.存在：Toast提示：重复的唯一码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.将原有唯一码及对应的入库信息缓存，待【确认库位】后添加/编辑至[入库明细]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.本次扫码：增加'1'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.累计入库：增加'数量'值</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">3.将识别出的'唯一码'及唯一码对应的物料信息(物料名称、编码、颜色、规格)至[入库信息页]</span></p><p><span>4.根据识别的“唯一码”是否在[当前采购入库明细]中、[物料库存日志-明细日志]中存在记录，对字段中</span><span style=\"color:#02A7F0;\">赋默认值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.不存在于[当前采购入库明细](新增)，无[物料库存日志-明细日志]记录</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">全部可编辑字段均为空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.不存在于[当前采购入库明细](新增)，有[物料库存日志-明细日志]记录</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">清空'数量'编辑域的值，其他字段取唯一码上已有值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.存在于[当前采购入库明细](编辑)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.取已填写的值，用于修改</span></p>",bu="12",bv="c1ee7f38080d49d49f4ccbd7ab01b05d",bw="确认库位",bx="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">校验当前“数量”编辑域</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">1.“数量”非空且＞0：通过校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">2.“数量”空或≤0：Toast提示'请输入数量'</span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">调用摄像头，进行扫码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.识别扫码字符串是否属于[物料仓库]中的库位编码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.不属于：返回Toast提示‘无法识别的库位编码’；停留在当前入库信息页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.属于：本次入库缓存中的'唯一码'若现存在于[物料库存-库存明细]中(即当前'实际库存'＞0)，校验当前该唯一码所属的仓库是否与当前扫码识别的'库位编码'所属的仓库一致</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.任意不一致：Toast提示“已有库存的唯一码与当前仓库不一致”&nbsp; (防止唯一码在原仓库被</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">锁库单</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">占用)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.均一致：通过校验；将本次的唯一码入库数据缓存至用户</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">2.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">将本次累计扫码及当前“唯一码”所属的物料SKU新增/修改至[入库列表]中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.未存在的SKU：使其它卡片下移，增加当前SKU至顶部；计算后记录</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">入库标签</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">和</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">入库数量</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.存在的SKU：即时更新该所属的SKU的汇总</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">入库标签</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">及</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">入库数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">3.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">将本次累计扫码及当前“唯一码”中填写的入库信息新增/修改至[入库列表：物料明细]中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.新增：新增至对应SKU入库明细内清单最底部</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.修改：在原入库明细内清单位置不变，刷新对应的唯一码入库信息</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">4.Toast提示：操作成功(</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">识别到的库位编码</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">5.返回页面至[入库列表]页</span></p>",by="13",bz="56f6780441e241e9995ce5c84708e0dd",bA="清空数据",bB="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">弹窗</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">确认是否清除</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.二次确认后移除</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">当前账户在[采购入库-当前采购单]下缓存的“入库明细”数据</span></p>",bC="14",bD="4356de7716434dfdbd20bf84e7e235f5",bE="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">卡片描述</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.物料编码：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">展示全</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，一般字符串长度不会超限；若超出单行宽度时换行展示，注意换行开始的位置是展示字段不是从标题开始</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.物料名称：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">仅展示单行宽度的字符</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，多余部分使用'…'进行补足；如原型图所示</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">3.颜色、规格：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">仅展示固定宽度的字符</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，多余部分使用'…'进行补足；如原型图所示；颜色和规格在单行中均占50%的宽度</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">4.入库标签/数量：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 4.1 使用' / '将入库标签数量与入库数量进行分隔</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 4.2 入库标签：其SKU下'唯一码'的个数</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 4.3 入库数量：其SKU下'唯一码'的入库数量的汇总；使用红色字体标识</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">5.单据物料：该SKU是否为采购订单内包含的</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; 5.1 是：黑色字体</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; 5.2 否：蓝色字体</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">6.【点击】跳转至SKU对应[入库明细]页展示其“唯一码’相关信息</span></p>",bF="15",bG="04f3e232065a4dd98a2d987df98e2933",bH="扫描物料",bI="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">调用摄像头，进行扫码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.校验识别的字符串是否为系统内生成过的“唯一码”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.生成过：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.未生成：返回Toast提示‘未生成的物料唯一码’；停留在当前列表页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.若[配置管理&gt;&gt;仓库配置：采购入库范围]为“仅单据物料”时，校验识别的“唯一码”所属的SKU是否为当前采购单中包含的</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.是单据物料：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.非单据物料：Toast提示‘仅支持单据内物料’；停留在当前入库信息页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">通过校验，将识别的'唯一码'及相关参数传至[入库信息页]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.若“唯一码”已存在于本次入库的[入库明细]中，将已填写的入库信息(全部字段)传至[入库信息页]后支持修改</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.若“唯一码”未存在于本次入库的[入库明细]中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.本次扫码：初始化为0</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.累计入库：初始化为0</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; c.将识别出的'唯一码'及唯一码对应的物料信息(物料名称、编码、颜色、规格)至[入库信息页]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; d.</span><span>根据识别的“唯一码”是否在[当前采购入库明细]中、[物料库存日志-明细日志]中存在记录，对字段中</span><span style=\"color:#02A7F0;\">赋默认值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.不存在于[当前采购入库明细](新增)，无[物料库存日志-明细日志]记录：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">全部可编辑字段均为空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.不存在于[当前采购入库明细](新增)，有[物料库存日志-明细日志]记录：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">清空'数量'编辑域的值，其他字段取唯一码上已有值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iii.存在于[当前采购入库明细](编辑)：取已填写的值，用于修改</span></p>",bJ="16",bK="19e7badb73c848fa8f16383023e5f692",bL="确认入库",bM="<p><span>1.校验“单据物料==是”的SKU卡片与选中的“关联单据(采购单)”中设定的'入库上限%'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.当前SKU在采购订单中对应的SKU存在任意行的'入库上限%'设定为空：该SKU通过校验</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.当前SKU在采购订单中对应的SKU设定的'入库上限%'均非空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 剩余支持入库数量 =该SKU在采购订单中</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#F59A23;\">Σ'采购数量*(1+入库上限%)'</span><span>-关联该采购单进行采购入库的'已通过'的入库单</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#F59A23;\">Σ'入库数量'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b1.当前'入库数量' ≤&nbsp; 剩余支持入库数量：通过校验</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b2.当前'入库数量' ＞ 剩余支持入库数量：Toast提示：超过采购入库上限（</span><span style=\"color:#6300BF;\">物料编码/物料规格/物料颜色</span><span>）</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.校验当前的入库明细中是否包含在[物料库存-库存明细]中的唯一码所属的仓库是否与当前入库明细中识别的&quot;库位编码&quot;所属的仓库不一致</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">不包含：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">弹窗</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">确认入库信息</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a1.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">二次确认最终按逻辑生成入库单</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">包含：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">跳转[重复唯一码]页面</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，展示当前入库明细中存在与[物料库存-库存明细]中的唯一码，但&quot;库位编码&quot;所属的仓库不一致的唯一码</span></p>",bN="17",bO="06cd250feb8743ba801218219451848d",bP="确认",bQ="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">清空当前账户在[采购入库-当前采购单]下缓存的“入库明细”数据</span></p>",bR="18",bS="d11b77774126467c83f353fa8a3c92df",bT="19",bU="2f404f1aff944628bdc7caeaca1636af",bV="唯一码",bW="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">点击将对应'唯一码'及相关参数传至[入库信息编辑页]，用以编辑唯一码的入库信息</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">将“唯一码”上已填写的入库信息(全部字段)传至[入库信息编辑页]后支持修改</span></p>",bX="20",bY="3e2ad48fd307449396c29946422d3523",bZ="(单元格)",ca="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.直接将对应行唯一码移除，返回Toast提示：移除成功</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.若已是明细中最后一个唯一码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.将这个SKU卡片从入库清单页移除</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">页面返回至[入库列表]页</span></p>",cb="21",cc="67d0ed0077ec4d7699a1f8b72dfa0f1d",cd="* 库位：",ce="<p><span>1.禁用，仅可通过扫码库位识别后覆盖现有的库位</span></p><p><span>2.点击右侧扫码图标，调用摄像头</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.识别扫码字符串是否属于[物料仓库]中的库位编码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.不属于：返回Toast提示‘无法识别的库位编码’；停留在当前入库信息编辑页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.属于：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.校验识别的‘库位编码’的所属仓库是否与当前“唯一码”现存于[物料库存-库存明细]中的仓库一致</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.不一致：返回Toast提示‘已有库存的唯一码与当前仓库不一致’；停留在当前入库信息编辑页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.一致：将识别的库位编码覆盖至当前编辑域</span></p>",cf="22",cg="036048165771431b951455083da67f37",ch="确认修改",ci="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">1.校验“数量”非空且＞0，否则Toast提示'请输入数量'</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">2.校验“库位”非空，否则Toast提示'扫码库位'</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">3.将当前入库信息上填写值覆盖至当前'唯一码'</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">4.返回Toast提示：编辑成功</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">5.返回[入库明细]页</span></p>",cj="23",ck="3f4d72a6f030451488afec93e367f3b8",cl="提示",cm="<p><span>入库种类：列表SKU的数量</span></p><p><span>入库标签：Σ入库标签</span></p><p><span>入库数量：Σ入库数量</span></p>",cn="24",co="92a8a48960b04232ad236a5fbf54a55d",cp="关联生产：",cq="<p><span>1.初始化默认值</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.若当前采购订单下包含的[生产订单]数量==1；默认将该生产订单号填充至“关联生产”；且</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">禁用</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.若当前采购订单下包含的[生产订单]数量 ＞1；清空“关联生产”中已选中的值；且</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">启用</span></p><p><span>2.数据源：当前采购订单下包含的[生产订单]去重</span></p>",cr="25",cs="a4188be529364af1bcc464964e9a3ca6",ct="确定",cu="<p><span>1.</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">按照多个'唯一码'在入库信息中填写的'库位编码'所属的“仓库”分开生成</span><span>入库单(RKD)</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a.唯一码的共计跨了几个库位的仓库就生成几个入库单</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b.入库类型为'采购入库'</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.关联单据为对应的采购订单(当前页面未展示具体采购订单，仅展示采购关联单)</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.供应商为采购订单对应的'供应商'</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; c.入库单的单据状态跟随系统审批流配置；并且记录当前操作人和操作时间至创建/更新人及时间</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; d.入库物料明细</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.唯一码入库的库位编码在哪个仓库，就将其记录在对应仓库的入库单内</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; e.入库物料汇总</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.数量为入库物料明细的SKU汇总成的入库数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.入库单价根据是否单据物料进行取值</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; </span><span>⬤</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"> “单据物料”=='是'，“入库单价”按采购订单中的'采购单价'</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; </span><span>⬤ </span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">“单据物料”=='否'，“入库单价”使用[仓库配置&gt;&gt;小程序默认单价&gt;&gt;采购入库(非单据)]选中的计算方式</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.Toast提示：操作成功</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">3.跳转至'菜单页'</span></p>",cv="26",cw="f015281632344637a7a2981ed4f35079",cx="<p><span>1.关闭筛选面板但缓存当前填写的字段值，再次打开面板时仍展示</span></p><p><span>2.列表筛选结果为当前多字段模糊搜索的交集</span></p>",cy="27",cz="bcfdc24dcaa940e5a85de5fb356e20b7",cA="库位",cB="<p><span>该唯一码在当前缓存中入库明细的“库位编码”</span></p>",cC="28",cD="67fb89ab5bc74a6f9f1f21037a258d72",cE="原库位",cF="<p><span>该唯一码在实际库存中存在的“库位编码”；若库位编码为空，仅展示其'仓库编码'</span></p>",cG="29",cH="a2906b8144a84fea9f539f04a0b92ce1",cI="确认移除",cJ="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.清除当前用户在该采购入库单内入库明细中上述唯一码的缓存数据</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.返回至[入库列表]页</span></p>",cK="style",cL="baseStyle",cM="627587b6038d43cca051c114ac41ad32",cN="pageAlignment",cO="center",cP="fill",cQ="fillType",cR="solid",cS="color",cT=0xFFFFFFFF,cU="image",cV="imageAlignment",cW="near",cX="imageRepeat",cY="auto",cZ="favicon",da="sketchFactor",db="0",dc="colorStyle",dd="appliedColor",de="fontName",df="Applied Font",dg="borderWidth",dh="borderVisibility",di="borderFill",dj=0xFF797979,dk="cornerRadius",dl="cornerVisibility",dm="outerShadow",dn="on",dp=false,dq="offsetX",dr=5,ds="offsetY",dt="blurRadius",du="spread",dv="r",dw=0,dx="g",dy="b",dz="a",dA=0.349019607843137,dB="adaptiveStyles",dC="interactionMap",dD="diagram",dE="objects",dF="id",dG="f4911a0ab42745e89c36abb6edd43feb",dH="friendlyType",dI="手机",dJ="referenceDiagramObject",dK="styleType",dL="visible",dM=true,dN=450,dO=800,dP="location",dQ="x",dR=1200,dS="y",dT="imageOverrides",dU="masterId",dV="4fac3643f4954cc4b8de2be8db632c44",dW="5c5bdc78899c414d8798f3e0a062ce36",dX=1800,dY="d33cc6d3f8c344458ffb107eabbe38cf",dZ="调整物料明细",ea="表格",eb="table",ec=410,ed=120,ee=1820,ef=265,eg="58b6ebdeb53b4760bc757d4a042aab2e",eh="单元格",ei="tableCell",ej="fontWeight",ek="700",el=60,em=30,en="2b919df770544924b45cd529b520fb2f",eo="fontSize",ep="12px",eq=0xFFD7D7D7,er=310,es="horizontalAlignment",et="left",eu="images",ev="normal~",ew="images/直接入库__240704_/u7128.png",ex="28f7aaf0a51d4156a65b8d514be37c0d",ey="2f404f1aff944628bdc7caeaca1636af",ez=110,eA="images/直接入库__240704_/u7125.png",eB="829c290aba6344cfa79b4c67b35fd63e",eC="foreGroundFill",eD=0xFF70B603,eE="opacity",eF=1,eG="9adda6e5f58e424e991657a5d6d0919a",eH="66b9a8500da3471582565295b44895de",eI="5e8055cf94f044709a89fa00e5de8c15",eJ=90,eK="5b084ac43c33431d90963b2a89e06c8c",eL="3e2ad48fd307449396c29946422d3523",eM=40,eN=3